// Populate the homepage "by the numbers" + freshness line from the shipped
// datasets so they stay in sync with the repo automatically — no hand-editing
// index.md on every curated-data refresh. The HTML keeps sensible fallback
// values for no-JS / pre-fetch; this script overwrites them once JSON loads.
//
// Sources (regenerated by `make docs-data`):
//   malicious-packages.json -> curated-entry count + distinct ecosystems
//   skills.json             -> skills count
//   stats.json              -> cve / secret / integration counts + freshness
//   db-history.json         -> DB size over time (for 30-day growth)
//
// Mirrors the client-side rendering used by Coverage / Threat-Intel. Hooks
// Material's `document$` so it survives instant navigation.
document$.subscribe(function () {
  if (!document.querySelector("[data-sv-stat],[data-sv-card],[data-sv-freshness]")) return;

  function dataURL(p) { return new URL(p, document.baseURI).href; }
  function getJSON(p) { return fetch(dataURL(p)).then(function (r) { return r.json(); }); }
  function setStat(key, value) {
    var el = document.querySelector('[data-sv-stat="' + key + '"]');
    if (el && value != null) el.textContent = String(value);
  }
  function setCard(key, text) {
    var el = document.querySelector('[data-sv-card="' + key + '"]');
    if (el && text) el.textContent = text;
  }

  getJSON("assets/data/malicious-packages.json").then(function (d) {
    var entries = d.entries || [];
    var total = typeof d.count === "number" ? d.count : entries.length;
    var ecos = {};
    entries.forEach(function (e) { if (e.ecosystem) ecos[e.ecosystem] = 1; });
    var nEcos = Object.keys(ecos).length;
    var totalStr = total.toLocaleString("en-US");
    setStat("malicious", totalStr);
    setStat("ecosystems", nEcos);
    setCard(
      "supply",
      totalStr + " web-cited malicious-package entries across " + nEcos +
        " ecosystems + typosquats. Browse the curated canon →"
    );
  }).catch(function () { /* keep static fallback */ });

  getJSON("assets/data/skills.json").then(function (d) {
    setStat("skills", (d.skills && d.skills.length) || d.count);
  }).catch(function () { /* keep static fallback */ });

  Promise.all([
    getJSON("assets/data/stats.json"),
    getJSON("assets/data/db-history.json").catch(function () { return { snapshots: [] }; }),
  ]).then(function (res) {
    var d = res[0], hist = res[1] || {};
    setStat("cve", d.cve_patterns);
    setStat("secret", d.secret_patterns);
    setStat("integrations", d.assistant_integrations);
    if (d.secret_patterns != null) {
      setCard(
        "secrets",
        d.secret_patterns + " secret-detection patterns optimised for " +
          "AI-assistant context, with entropy and hotword-proximity scoring."
      );
    }
    renderFreshness(d.freshness, hist.snapshots || []);
  }).catch(function () { /* keep static fallback */ });

  // Growth in the last `days` days: latest total minus the total as of the
  // cutoff (the latest snapshot on/before cutoff; if our history is shorter
  // than the window, the earliest snapshot — so it reads as a true lower bound
  // of "added within the last N days").
  function growthOverDays(snaps, days) {
    if (!snaps.length) return 0;
    var sorted = snaps.slice().sort(function (a, b) { return a.date < b.date ? -1 : 1; });
    var latest = sorted[sorted.length - 1];
    var cutoff = new Date(Date.now() - days * 86400000).toISOString().slice(0, 10);
    var baseline = sorted[0];
    for (var i = 0; i < sorted.length; i++) {
      if (sorted[i].date <= cutoff) baseline = sorted[i];
    }
    return Math.max(0, latest.total - baseline.total);
  }

  function renderFreshness(f, snaps) {
    var el = document.querySelector("[data-sv-freshness]");
    if (!el || !f || !f.curated_last_updated) return;
    var when = new Date(f.curated_last_updated + "T00:00:00Z");
    var nice = when.toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" });
    var parts = ["Curated database refreshed " + nice];
    var growth = growthOverDays(snaps, 30);
    if (growth > 0) parts.push("+" + growth.toLocaleString("en-US") + " entries in the last 30 days");
    if (f.ossf_commit) parts.push("OSSF malicious-packages @ " + f.ossf_commit);
    el.textContent = parts.join(" · ");
  }
});
